import React, { useState } from "react";
import API from "../api";
import Navbar from "../components/Navbar";
import VoiceInput from "../components/VoiceInput";
import Chatbot from "../components/Chatbot";
import { downloadReport } from "../utils/downloadReport";

export default function Dashboard({ setPage }) {
  const [symptoms, setSymptoms] = useState("");
  const [result, setResult] = useState(null);

  const predict = async () => {
    const res = await API.post("/predict", {
      symptoms: symptoms.split(",")
    });
    setResult(res.data);
  };

  return (
    <>
      <Navbar setPage={setPage} />

      <div style={{ padding: 20 }}>
        <div className="glass">
          <input onChange={e => setSymptoms(e.target.value)} />

          <VoiceInput setSymptoms={(s) => setSymptoms(s.join(","))} />

          <button onClick={predict}>Predict</button>
        </div>

        {result && (
          <>
            <div className="glass">
              <h3>{result.final_prediction.disease}</h3>
              <p>{result.final_prediction.confidence}%</p>

              <button onClick={() => downloadReport(result)}>
                Download Report
              </button>
            </div>

            <Chatbot
              disease={result.final_prediction.disease}
              precautions={result.disease_info.precautions}
            />
          </>
        )}
      </div>
    </>
  );
}
